#include <vector>
#include <algorithm>
using namespace std;

struct FenwickTree {
    vector<long long> tree;
    int size;
    FenwickTree(int size) : size(size), tree(size + 2, 0) {}
    void update(int index, long long delta) {
        while (index <= size) {
            tree[index] += delta;
            index += index & -index;
        }
    }
    long long query(int index) {
        long long res = 0;
        while (index > 0) {
            res += tree[index];
            index -= index & -index;
        }
        return res;
    }
    long long range_query(int l, int r) {
        return query(r) - query(l - 1);
    }
};

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    int n = nums.size();
    vector<FenwickTree> ft(6);
    for (int i = 0; i < 6; ++i) {
        ft[i].size = n;
    }

    // Precompute depth for each number
    for (int i = 0; i < n; ++i) {
        long long x = nums[i];
        long long depth = 0;
        long long current = x;
        while (current != 1) {
            current = __builtin_popcountll(current);
            depth++;
            if (depth > 5) break;
        }
        if (depth <= 5) {
            ft[depth].update(i + 1, 1); // 1-based index
        }
    }

    vector<long long> answer;
    for (auto& q : queries) {
        if (q[0] == 1) {
            int l = q[1];
            int r = q[2];
            int k = q[3];
            if (k < 0 || k > 5) {
                answer.push_back(0);
                continue;
            }
            // query the k-th FenwickTree for [l, r]
            long long res = ft[k].range_query(l + 1, r + 1);
            answer.push_back(res);
        } else {
            int idx = q[1];
            long long val = q[2];
            // process old value
            long long old_val = nums[idx];
            long long old_depth = 0;
            long long current = old_val;
            while (current != 1) {
                current = __builtin_popcountll(current);
                old_depth++;
                if (old_depth > 5) break;
            }
            if (old_depth <= 5) {
                ft[old_depth].update(idx + 1, -1);
            }
            // update the nums array
            nums[idx] = val;
            // compute new depth
            long long new_depth = 0;
            long long current_new = val;
            while (current_new != 1) {
                current_new = __builtin_popcountll(current_new);
                new_depth++;
                if (new_depth > 5) break;
            }
            if (new_depth <= 5) {
                ft[new_depth].update(idx + 1, 1);
            }
        }
    }
    return answer;
}

